insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А после того как Иисус <а>родился в <1б>Вифлееме Иудейском в дни царя <в>Ирода, вот, прибыли в Иерусалим <г>волхвы с двостока',2,1,2,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И сказали: Где Тот, кто родился <1а>Царём Иудейским? Ибо мы увидели Его <2б>звезду при её восхождении и пришли <в>поклониться Ему.',2,1,2,2);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, услышав это, царь Ирод встревожился, и весь Иерусалим с ним.',2,1,2,3);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, собрав всех главных <1а>священников и <б>книжников народа, он спросил у них, где родится Христос.',2,1,2,4);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И они сказали ему: В <а>Вифлееме Иудейском, ибо так написано через пророка:',2,1,2,5);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('«<а>И ты, Вифлеем, земля Иуды, отнюдь не малейший среди <1>предводителей Иуды; ибо из тебя выйдет <б>Правитель, который будет <в>пасти Мой народ, Израиля».',2,1,2,6);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Тогда Ирод, тайно позвав волхвов, точно узнал у них время появления звезды.',2,1,2,7);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, послав их в Вифлеем, сказал: Пойдите, точно выясните о ребёнке. А когда найдёте Его, сообщите мне, чтобы и я пришёл и поклонился Ему.',2,1,2,8);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И они, выслушав царя, пошли, и вот, <1а>звезда, которую они увидели при её восхождении, вела их, пока не пришла и не остановилась над местом, где был ребёнок.',2,1,2,9);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, увидев звезду, они чрезвычайно обрадовались великой радостью.',2,1,2,10);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, войдя в <1>дом, они увидели <а>ребёнка с <б>Марией, Его матерью. И, пав, <2>поклонились Ему и, открыв свои сокровищницы, преподнесли Ему <3в>дары: <г>золото, <д>ладан и <е>мирру.',2,1,2,11);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, получив во <а>сне божественное указание не <1>возвращаться к Ироду, они <2>другим путём удалились в свою страну.',2,1,2,12);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А когда они удалились, вот, <а>ангел Господень является во <б>сне Иосифу и говорит: Встань, возьми ребёнка и Его мать, и беги в <в>Египет, и будь там, пока я не скажу тебе; ибо Ирод намерен искать ребёнка, чтобы уничтожить Его.',2,1,2,13);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И он встал и взял ребёнка и Его мать ночью, и удалился в Египет,',2,1,2,14);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И был там до смерти Ирода, чтобы <1а>исполнилось сказанное Господом через пророка, который говорит: «<б>Из Египта Я призвал Моего <2в>Сына».',2,1,2,15);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Тогда Ирод, увидев, что он осмеян волхвами, сильно разгневался и, послав людей, <1>расправился со всеми мальчиками, которые были в Вифлееме и во всех его пределах, от двух лет и младше, согласно времени, которое точно узнал у волхвов.',2,1,2,16);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Тогда <а>исполнилось сказанное через пророка Иеремию, который говорит:',2,1,2,17);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('«<а>Голос в Раме был слышен, плач и великое сетование: <1>Рахиль оплакивала своих детей и не хотела утешиться, потому что их уже нет».',2,1,2,18);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А когда Ирод умер, вот, ангел Господень является во <а>сне Иосифу в Египте',2,1,2,19);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И говорит: Встань, возьми ребёнка и Его мать и иди в землю Израиля, ибо <а>умерли те, кто ищет <1>жизни ребёнка.',2,1,2,20);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И он встал и взял ребёнка и Его мать и вошёл в землю Израиля.',2,1,2,21);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Но, услышав, что Архелай царствует над Иудеей вместо своего отца Ирода, он побоялся идти туда и, получив во <а>сне божественное указание, удалился в области <1б>Галилеи.',2,1,2,22);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И он пришёл и поселился в городе, который называется <1а>Назарет, чтобы <б>исполнилось сказанное через <2>пророков, что Он будет назван <3>Назарянином.',2,1,2,23);
